    idx_len = bson_uint32_to_string(1, &key, idx, sizeof idx);
    BSON_APPEND_DOCUMENT_BEGIN(&meta_array, key, &limit_doc);
    BSON_APPEND_INT32(&limit_doc, "$limit", 1);
