You can use [faceted navigation](fts-facet-ref) in queries that use the
[$search](pipe.$search) and [$searchMeta](pipe.$searchMeta) stages. In this
section, you will connect to your cluster and the run the sample query
against the `sample_mflix.movies` collection using the
[$searchMeta](pipe.$searchMeta) or [$search](pipe.$search) stage to group the
`genre` and `year` fields into buckets. To optimize performance:

- Use [$searchMeta](pipe.$searchMeta) stage if you only need the `facet` metadata.

- Use [$search](pipe.$search) stage if you want to retrieve both the query
  results and the `facet` metadata.

The code example performs the following tasks:

- Imports `mongodb` packages and dependencies.

- Establishes a connection to your cluster.

- Uses the following searchMeta clauses to query the collection:

  - [near](near-ref) to search for movies released with a
    `pivot` distance from  `origin` of approximately three months
    from November 11, 1921

  - `facets` to request the number of movies in each genre in the
    `genres` string array field and the number of movies in the years
    1910 to 1939, inclusive

- Iterates over the cursor to print the documents that match the
  query.

You can run this query using [$searchMeta](pipe.$searchMeta) or using
[$search](pipe.$search) with the `SEARCH_META` aggregation variable.

$searchMeta

```go
package main

import (
	"context"
	"fmt"
	"time"

	"go.mongodb.org/mongo-driver/v2/bson"
	"go.mongodb.org/mongo-driver/v2/mongo"
	"go.mongodb.org/mongo-driver/v2/mongo/options"
)

func main() {
	// Connects to your Atlas cluster
	client, err := mongo.Connect(options.Client().ApplyURI("<connection-string>"))
	if err != nil {
		panic(err)
	}
	defer client.Disconnect(context.TODO())

	// Sets the namespace
	collection := client.Database("sample_mflix").Collection("movies")

	// Defines the pipeline stages
	searchStage := bson.D{{Key: "$searchMeta", Value: bson.M{
		"index": "facet-tutorial",
		"facet": bson.M{
			"operator": bson.M{
				"near": bson.M{
					"path":   "released",
					"origin": time.Date(1921, time.November, 1, 0, 0, 0, 0, time.UTC),
					"pivot":  7776000000},
			},
			"facets": bson.M{
				"genresFacet": bson.M{
					"path": "genres",
					"type": "string"},
				"yearFacet": bson.M{
					"path":       "year",
					"type":       "number",
					"boundaries": bson.A{1910, 1920, 1930, 1940}},
			}}}}}

	// Runs the pipeline
	cursor, err := collection.Aggregate(context.TODO(), mongo.Pipeline{searchStage})
	if err != nil {
		panic(err)
	}

	// Prints the results
	var results []bson.D
	if err = cursor.All(context.TODO(), &results); err != nil {
		panic(err)
	}
	for _, result := range results {
		fmt.Println(result)
	}
}

```

$search with $$SEARCH\_META

```go
package main

import (
	"context"
	"fmt"
	"time"

	"go.mongodb.org/mongo-driver/v2/bson"
	"go.mongodb.org/mongo-driver/v2/mongo"
	"go.mongodb.org/mongo-driver/v2/mongo/options"
)

func main() {
	// Connects to your Atlas cluster
	client, err := mongo.Connect(options.Client().ApplyURI("<connection-string>"))
	if err != nil {
		panic(err)
	}
	defer client.Disconnect(context.TODO())

	// Sets the namespace
	collection := client.Database("sample_mflix").Collection("movies")

	// Defines the pipeline stages
	searchStage := bson.D{{Key: "$search", Value: bson.M{
		"index": "facet-tutorial",
		"facet": bson.M{
			"operator": bson.M{
				"near": bson.M{
					"path":   "released",
					"origin": time.Date(1921, time.November, 1, 0, 0, 0, 0, time.UTC),
					"pivot":  7776000000},
			},
			"facets": bson.M{
				"genresFacet": bson.M{
					"path": "genres",
					"type": "string"},
				"yearFacet": bson.M{
					"path":       "year",
					"type":       "number",
					"boundaries": bson.A{1910, 1920, 1930, 1940}},
			},
		},
	}}}

	facetStage := bson.D{{Key: "$facet", Value: bson.D{
		{Key: "meta", Value: bson.A{
			bson.D{{Key: "$replaceWith", Value: "$$SEARCH_META"}},
			bson.D{{Key: "$limit", Value: 1}},
		}},
	}}}
	setStage := bson.D{{Key: "$set", Value: bson.D{
		{Key: "meta", Value: bson.D{
			{Key: "$arrayElemAt", Value: bson.A{"$meta", 0}},
		}},
	}}}

	// Runs the pipeline
	cursor, err := collection.Aggregate(context.TODO(), mongo.Pipeline{searchStage, facetStage, setStage})
	if err != nil {
		panic(err)
	}

	// Prints the results
	var results []bson.D
	if err = cursor.All(context.TODO(), &results); err != nil {
		panic(err)
	}
	for _, result := range results {
		fmt.Println(result)
	}
}

```

